      }
    },
    "factorsNegative": {
      "type": "array",
      "description": "Specific record facts that weaken the profile",
      "items": {
        "type": "string"
      }
    },
    "dataGaps": {
      "type": "array",
      "description": "Fields whose absence limited the assessment",
      "items": {
        "type": "string"
      }
    },
    "reasoning": {
      "type": "string",
      "description": "How the score was reached, citing record fields"
    }
  }
}

